def build_select_query(schema_name, table_name, columns, filters, order_by,
                       limit, offset, aggregate=None, group_by=None):
    """
    Build a parameterized SELECT query using psycopg2.sql module.
    All identifiers use sql.Identifier() for safe quoting.
    All values use parameterized placeholders.
    """
    params = []

    # Build column list
    if aggregate and group_by:
        # Aggregate query
        select_parts = []
        for gb_col in group_by:
            select_parts.append(sql.Identifier(gb_col))

        if isinstance(aggregate, dict):
            for func_name, agg_col in aggregate.items():
                func_name = func_name.upper()
                if func_name not in ALLOWED_AGGREGATES:
                    raise ValueError(f"Aggregate function '{func_name}' not allowed")
                if agg_col == '*':
                    select_parts.append(
                        sql.SQL("{}(*)").format(sql.SQL(func_name))
                    )
                else:
                    select_parts.append(
                        sql.SQL("{}({})").format(
                            sql.SQL(func_name),
                            sql.Identifier(agg_col)
                        )
                    )

        select_clause = sql.SQL(", ").join(select_parts)
    elif columns:
        select_clause = sql.SQL(", ").join(
            sql.Identifier(col) for col in columns
        )
    else:
        select_clause = sql.SQL("*")

    # Build FROM clause with schema
    table_ref = sql.SQL("{}.{}").format(
        sql.Identifier(schema_name),
        sql.Identifier(table_name)
    )

    # Start building the query
    query = sql.SQL("SELECT {} FROM {}").format(select_clause, table_ref)

    # Build WHERE clause
    if filters:
        where_parts = []
        for f in filters:
            col = f['column']
            op = f['operator']

            if op in ('IS NULL', 'IS NOT NULL'):
                where_parts.append(
                    sql.SQL("{} {}").format(
                        sql.Identifier(col),
                        sql.SQL(op)
                    )
                )
            elif op == 'BETWEEN':
                where_parts.append(
                    sql.SQL("{} BETWEEN {} AND {}").format(
                        sql.Identifier(col),
                        sql.Placeholder(),
                        sql.Placeholder()
                    )
                )
                params.append(f['value_from'])
                params.append(f['value_to'])
            elif op in ('IN', 'NOT IN'):
                values = f['value']
                if not isinstance(values, list) or len(values) == 0:
                    raise ValueError(f"IN/NOT IN requires a non-empty list of values")
                if len(values) > 1000:
                    raise ValueError("Too many values for IN clause (max 1000)")
                placeholders = sql.SQL(", ").join(
                    sql.Placeholder() for _ in values
                )
                where_parts.append(
                    sql.SQL("{} {} ({})").format(
                        sql.Identifier(col),
                        sql.SQL(op),
                        placeholders
                    )
                )
                params.extend(values)
            else:
                where_parts.append(
                    sql.SQL("{} {} {}").format(
                        sql.Identifier(col),
                        sql.SQL(op),
                        sql.Placeholder()
                    )
                )
                params.append(f['value'])

        if where_parts:
            query = sql.SQL("{} WHERE {}").format(
                query,
                sql.SQL(" AND ").join(where_parts)
            )

    # GROUP BY clause
    if group_by:
        group_clause = sql.SQL(", ").join(
            sql.Identifier(col) for col in group_by
        )
        query = sql.SQL("{} GROUP BY {}").format(query, group_clause)

    # ORDER BY clause
    if order_by:
        order_parts = []
        for ob in order_by:
            direction = ob.get('direction', 'ASC').upper()
            if direction not in ALLOWED_ORDER_DIRECTIONS:
                raise ValueError(f"Invalid order direction: {direction}")
            order_parts.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(ob['column']),
                    sql.SQL(direction)
                )
            )
        query = sql.SQL("{} ORDER BY {}").format(
            query,
            sql.SQL(", ").join(order_parts)
        )

    # LIMIT and OFFSET - use parameterized values
    query = sql.SQL("{} LIMIT {} OFFSET {}").format(
        query,
        sql.Placeholder(),
        sql.Placeholder()
    )
    params.append(limit)
    params.append(offset)

    return query, params


