@app.route('/api/v1/tables', methods=['GET'])
@require_api_key
def list_tables():
    """List all allowed tables."""
    return jsonify({
        'tables': sorted(list(ALLOWED_TABLES)),
        'schemas': sorted(list(ALLOWED_SCHEMAS)),
    }), 200


@app.route('/api/v1/tables/<table_name>/columns', methods=['GET'])
@require_api_key
def list_columns(table_name):
    """List columns for a specific allowed table."""
    try:
        valid, result = validate_table_name(table_name)
        if not valid:
            return jsonify({'error': result}), 400
        table_name = result

        schema_name = request.args.get('schema', 'public')
        valid, result = validate_schema_name(schema_name)
        if not valid:
            return jsonify({'error': result}), 400
        schema_name = result

        conn = get_db_connection()
        try:
            cursor = conn.cursor()
            try:
                cursor.execute(
                    "SELECT column_name, data_type, is_nullable "
                    "FROM information_schema.columns "
                    "WHERE table_schema = %s AND table_name = %s "
                    "ORDER BY ordinal_position",
                    (schema_name, table_name)
                )
                columns = [
                    {
                        'name': row[0],
                        'type': row[1],
                        'nullable': row[2] == 'YES',
                    }
                    for row in cursor.fetchall()
                ]

                if not columns:
                    return jsonify({'error': 'Table not found'}), 404

                return jsonify({
                    'table': table_name,
                    'schema': schema_name,
                    'columns': columns,
                }), 200
            finally:
                cursor.close()
        finally:
            conn.close()

    except OperationalError:
        return jsonify({'error': 'Database connection error'}), 503
    except Exception:
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/v1/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute("SELECT 1")
        cursor.close()
        conn.close()
        return jsonify({'status': 'healthy'}), 200
    except Exception:
        return jsonify({'status': 'unhealthy'}), 503


